import { getPatientId } from "./UIfacade/evacuationFacade";
import { getDivForCategory } from "./UIfacade/patientFacade";
getDivForCategory(getPatientId()!);

disableIf.content:
import { canCancelAction, getActionTemplateContext, isPlanActionButtonDisabled } from "./UIfacade/actionFacade";
  if (canCancelAction(getActionTemplateContext())) {
      // must have access to cancel button
    return false;
  }

if (isPlanActionButtonDisabled(getActionTemplateContext())) {
	return true;
}

const params = Context.interfaceState.state.evacuation.data;
Object.values(params).includes(undefined);

initialState.content:
import { UniqueAction } from "./game/common/actionType";
import { getActionTemplate } from "./UIfacade/actionFacade";
getActionTemplate(UniqueAction.EvacuationActionTemplate)!;

hideIf.content:
import { UniqueAction } from "./game/common/actionType";
import { getActionTemplate } from "./UIfacade/actionFacade";
getActionTemplate(UniqueAction.EvacuationActionTemplate) === undefined;
